(() => {
  const d = document;
  function r(f) {
    d.readyState !== "loading"
      ? f()
      : d.addEventListener("DOMContentLoaded", f, { once: !0 });
  }
  function h() {
    const p = location.pathname.replace(/\/$/, "") || "/";
    d.querySelectorAll(".nav-btn").forEach((a) => {
      const href = (a.getAttribute("href") || "").replace(/\/$/, "") || "/";
      href === p && a.classList.add("highlight");
    });
  }
  r(h);
})();
